var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"크윽!","JPN":"くうっ！","ENG":"Hngh!","TWN":"唔！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"방금까지 저급한 4종 침식체도 간신히 상대하는 수준이었는데…….","JPN":"先ほどまでは第4種侵食体になんとか対抗できる程度でしたが……","ENG":"You could barely face off with a lowly Category 4 just moments ago…","TWN":"剛剛和4類侵蝕體交手時明明還很勉強……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"짧은 시간에 급격히 성장했군요.","JPN":"この短時間で急激に成長したようですね。","ENG":"How rapidly you've grown in such a short span of time.","TWN":"在這麼短的時間內成長不少呢！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이것도 그 저주받은 늑대로서의 힘인가요?","JPN":"これも呪われた狼としての力でしょうか？","ENG":"Is this also a perk of being the Cursed Wolf?","TWN":"那也是因為你是受到詛咒的狼嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"알 바 아냐, 그딴 거!","JPN":"そんなもの知らない！","ENG":"I don't know, and I don't care!","TWN":"不關你的事！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"지금 내가 아는 건 여기서 널 쓰러트린다는 것뿐이야!","JPN":"今確かなのは、あんたをここで倒してやるってことだけ！","ENG":"All I know is that I'm going to take you down right here!","TWN":"我現在只知道一件事，就是要打倒你！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"후후…… 귀엽군요.","JPN":"ふふ……かわいいものですね。","ENG":"Haha… How amusing.","TWN":"呵呵……真是可愛。"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"성장했다고는 하지만 그래 봐야 아직은 부족한 힘.","JPN":"成長したとはいえ、まだ未熟の力。","ENG":"You may have grown stronger, but your powers are still not enough.","TWN":"雖說有成長不少，但能力還是有限。"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 이방인의 말대로 찌꺼기에 불과한 주제에 자신감만은 넘치는군요.","JPN":"あの異邦人の言うとおり、残滓にすぎないというのに自信だけは溢れていますね。","ENG":"Like the outsider said, you're brimming with confidence despite being merely residue.","TWN":"明明是個廢渣口氣卻不小呢。"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐라고?","JPN":"何だって？","ENG":"What?","TWN":"你說我什麼？"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"좋습니다. 장난은 이만 끝내기로 하지요.","JPN":"いいでしょう。お遊びはこれでおしまいです。","ENG":"Very well. Playtime is over.","TWN":"好了，玩笑話到此為止。"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"어차피 우리에게 필요한 것은 당신의 몸뚱이뿐.","JPN":"私たちに必要なものはあなたの体だけ。","ENG":"All we need is your body, after all.","TWN":"反正我們要的只有你的身體而已。"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"뇌를 파내어 이지를 상실한 후에도 그런 표정을 지을 수 있을지 궁금하군요.","JPN":"脳をえぐり理性を失った後も、そんな表情ができるのか見物ですね。","ENG":"We shall see if you'll still make that face once we've carved your brain out.","TWN":"等我把你的腦袋挖出來，我看你還能一臉囂張嗎！"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아, 걱정은 마세요. 저는 부활의 성녀, 루크레시아.","JPN":"心配は要りません。私は復活の聖女、ルクレシア。","ENG":"Oh, don't worry. I am the Saintess of Resurrection, after all.","TWN":"喔！不過不用擔心，因為我可是復活的聖女 露可蕾西亞。"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"비록 산송장으로 만들더라도 결코 죽이지는 않을 테니까요.","JPN":"空虚な抜け殻にしたとしても、決して殺すことはいたしません。","ENG":"We may turn you into a living corpse, but we won't kill you.","TWN":"我不會殺死你的，我會把你做成活死人。"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"그만 두시죠.","JPN":"そこまでです。","ENG":"That's enough.","TWN":"住手。"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"방금……? 내 공격이 튕겨 나갔어?","JPN":"今のは……？　私の攻撃が弾かれた？","ENG":"What…? Something deflected my attack?","TWN":"剛剛是……？我的攻擊被擋下了？"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"잠깐, 이 목소리는…….","JPN":"そんな、この声は……","ENG":"Wait… That voice…","TWN":"等等，這個聲音是……"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"설마…….","JPN":"まさか……","ENG":"No way…","TWN":"難道……"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배……?","JPN":"先輩……？","ENG":"Shiyoon...?","TWN":"是前輩……？"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"지금, 나 갖고 장난치는 거 아니지……?","JPN":"これって、ドッキリとかじゃないよね……？","ENG":"This isn't some kind of a nasty prank, is it?","TWN":"你不是在跟我開玩笑吧……？"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 물론이죠.","JPN":"ハハ、もちろんです。","ENG":"Haha, of course not.","TWN":"哈哈～當然不是。"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"이번엔 정말로 위험하긴 했지만……. 저도 펜릴 소대의 일원인 걸요.","JPN":"さっきは本当に危ないところでしたが……僕もフェンリル小隊の一員です。","ENG":"I nearly kicked the bucket this time… But I'm still a member of the Fenrir Squad.","TWN":"雖然這次是真的很危險……但好歹我也是芬里爾小隊的成員，"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"이런 데서 죽었다간 스승님에게 기초 훈련부터 다시 받게 될 겁니다.","JPN":"こんなところで死んだら、師匠に基礎訓練からやり直させられてしまいます。","ENG":"If I died in a place like this, the Master would put me through basic training again.","TWN":"要是死在這種地方，師父會叫我砍掉重練吧！"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"분명 용혈이 완전히 뽑혀 나와 빈 껍데기만 남았을 텐데?","JPN":"確かに龍血を完全に抜き取って、残骸だけが残っていたはず。","ENG":"But you must be nothing but an empty husk now, devoid of any Dragon Blood!","TWN":"你體內的龍血明明都抽出來了，現在不是應該只剩下一副空殼子嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 상태에서 회복 따윈 불가능합니다! 그런데 어떻게……!","JPN":"そんな状態から回復することなんて不可能です！　なのにどうやって……！","ENG":"Self-regeneration should be impossible in such a state! So how…?!","TWN":"在那種狀態下是不可能恢復的！為什麼你……！"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"글쎄요? 조상님들께서 쌓아 두신 공덕 덕분이라고 해 둘까요?","JPN":"さあ？　ご先祖様のおかげってことじゃないですかね。","ENG":"Who knows? I guess you could say I can thank my ancestors?","TWN":"這個嘛？可能我祖上積德吧？"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"무슨 헛소리를……!","JPN":"戯言を……！","ENG":"You expect me to believe such nonsense?!","TWN":"少跟我耍嘴皮子……！"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":" 크윽!","JPN":"くうっ！","ENG":" Hngh!","TWN":"唔！"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_03"},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"어이쿠. 놀라셨다면 죄송합니다, 성녀님.","JPN":"おっと、驚かせて申し訳ありません、聖女様。","ENG":"Whoops. Please excuse me if that startled you, dear Saintess.","TWN":"哎呀呀，聖女大人，嚇到你真是不好意思。"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"헛소리라고 하시니 조상님들께서 화가 잔뜩 나셨나 보네요.","JPN":"戯言なんて言うから、ご先祖様たちがご立腹になられたようです。","ENG":"You must have crossed my ancestors when you said that this is nonsense.","TWN":"可能因為你說我耍嘴皮子，所以祖先們有點生氣氣。"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배? 그 모습은 뭐야?","JPN":"先輩？　その姿はなに？","ENG":"Shiyoon? What’s with the new look?","TWN":"前輩？你那身裝扮是什麼？"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"설마 선배도 사장님한테 전투복을 받았던 거야?","JPN":"まさか、先輩も社長から戦闘服をもらっていたの？","ENG":"Did the Boss give you a new suit as well?","TWN":"前輩也有收到老闆給的戰鬥服嗎？？"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"아니요. 이건…… 아마 제 먼 선조께서 사용하던 물건인 것 같군요.","JPN":"いいえ。これは……おそらく僕の遠いご先祖様が使っていた物のようです。","ENG":"No. This… must be a hand-me-down from a distant ancestor of mine.","TWN":"不是……這好像是我的祖先使用過的東西吧？"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"제가 그 분들의 유산을 계승했다는 자격의 증표인 거겠죠.","JPN":"僕があの方々の遺産を継承したという資格の証なのでしょう。","ENG":"I guess it's meant to signify that I've inherited their legacy.","TWN":"證明我得到繼承他們遺產的認可。"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"자세히는 몰라도…… 좋은 거란 뜻이지?","JPN":"詳しくはわからないけど……いいモノってことだよね？","ENG":"I'm not sure what that's supposed to mean… but that's a good thing, right?","TWN":"雖然不是很明白……但應該是好事吧？"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그럼요. 이건 제 유년기가 끝났다는 선물이기도 하니까요.","JPN":"もちろんです。これは僕の幼年期が終わったお祝いのプレゼントでもありますから。","ENG":"Of course. It's also my coming-of-age gift, so to speak.","TWN":"當然囉！這是慶祝我長大成人的禮物。"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"자, 그럼 이제부터 납치범을 응징해 볼까요?","JPN":"さて、それじゃあ誘拐犯を懲らしめてあげましょうか？","ENG":"Now, then. Shall we bring my captors to justice?","TWN":"現在先好好處理一下綁架犯吧！"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"좋아! 어떻게 할까?","JPN":"いいよ！　どうする？","ENG":"Great! What should I do?","TWN":"好！前輩想怎麼做？"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"간단해요. 언제나 했던 대로 하는 거죠.","JPN":"簡単です。いつものようにやるだけです。","ENG":"It's simple. We do as we always have.","TWN":"很簡單，老樣子！"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"가세요, 미나 양.","JPN":"行ってください、ミナさん。","ENG":"Go, Mina.","TWN":"上吧！米娜！"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"뒤는 제게 맡기시고요.","JPN":"あとは僕がなんとかしますから。","ENG":"I'll take care of everything here.","TWN":"後面就交給我！"},"stage":{"bg":"CORRIDOR_03","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};